var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_NULL","text":{"KOREA":"저기…….","JPN":"あのさ……","ENG":"Hey...","TWN":"那個……"},"stage":{"bg":"UNDER","slots":{"L":null,"C":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"GRIL_KNIGHT_PAST_STAFF","text":{"KOREA":"응?","JPN":"ん？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"UNDER","slots":{"L":null,"C":{"char_id":"GRIL_KNIGHT_PAST_STAFF","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_NULL","text":{"KOREA":"왜 아까부터 여기 가만히 있는 거야? 혹시 길을 잃은 건 아니지?","JPN":"なんでさっきからここで止まってるの？　もしかして道に迷った？","ENG":"Why are you just standing here? You aren’t lost, are you?","TWN":"為什麼從剛才就一直站在這裡？你應該不是迷路吧？"},"stage":{"bg":"UNDER","slots":{"L":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRIL_KNIGHT_PAST_STAFF","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"GRIL_KNIGHT_PAST_STAFF","text":{"KOREA":"뭐야. 뜸들이길래 엄청 대단한 말이라도 하려나 했더니……","JPN":"なによ。もったいぶるからなんかすごいことでも言うのかと思ったら……","ENG":"Oh. I thought you were going to say something important after all that hesitating...","TWN":"什麼嘛，在那邊吞吞吐吐的，我還以為你會有什麼驚人的發言……"},"stage":{"bg":"UNDER","slots":{"L":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRIL_KNIGHT_PAST_STAFF","face":"UNIT_DESPAIR"}}}},{"id":"L8_1","type":"dialog","speaker":"GRIL_KNIGHT_PAST_STAFF","text":{"KOREA":"걱정하지 말고 얌전히 따라오기나 해. 의뢰인과는 이 근처에서 만나기로 했으니까.","JPN":"心配しないでおとなしくついてきて。依頼人とはこの辺りで会う予定だから。","ENG":"Don’t worry and just follow me quietly. I agreed to meet my contact around here.","TWN":"安啦，你乖乖跟著我就好，我和委託人約在這附近見面。"},"stage":{"bg":"UNDER","slots":{"L":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRIL_KNIGHT_PAST_STAFF","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_NULL","text":{"KOREA":"이 근처? 하수도에서 말이야?","JPN":"この辺り？　下水道で？","ENG":"Around here? You mean inside the sewers?","TWN":"這附近？下水道裡？"},"stage":{"bg":"UNDER","slots":{"L":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GRIL_KNIGHT_PAST_STAFF","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"GRIL_KNIGHT_PAST_STAFF","text":{"KOREA":"그, 그래! 내 말은 노예라 못 믿겠다는 거야?","JPN":"そ、そうよ！　奴隷の言うことは信じられない？","ENG":"T-that’s right! You can’t trust me since I’m a slave, is that it?","TWN":"對…對啊！因為我是奴隸你就懷疑我嗎？"},"stage":{"bg":"UNDER","slots":{"L":null,"C":{"char_id":"GRIL_KNIGHT_PAST_STAFF","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_NULL","text":{"KOREA":"그런 뜻이 아니라…….","JPN":"そういう意味じゃなくて……","ENG":"No, that's not what I meant...","TWN":"我不是這個意思……"},"stage":{"bg":"UNDER","slots":{"L":null,"C":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"PRIESTESS_NPC_WEST_WOMAN","text":{"KOREA":"시간을 제대로 지켰군요, 루크레시아.","JPN":"約束の時間どおりですね、ルクレシア。","ENG":"You’re on time, Lucrecia.","TWN":"很準時嘛，露可蕾西亞。"},"stage":{"bg":"UNDER","slots":{"L":null,"C":{"char_id":"PRIESTESS_NPC_WEST_WOMAN","face":"UNIT_IDLE"},"R":{"char_id":"KNIGHT_NPC_TEMPLE_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_NULL","text":{"KOREA":"저 기사들은…… 설마 여기까지 쫓아온 거야?","JPN":"あの騎士は……もしかしてここまで追って？","ENG":"Those knights... Don’t tell me that they followed us all the way here?!","TWN":"那些騎士……追到這裡來了嗎？"},"stage":{"bg":"UNDER","slots":{"L":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GRIL_KNIGHT_PAST_STAFF","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"GRIL_KNIGHT_PAST_STAFF","text":{"KOREA":"가만히 있어, 겁쟁아. 방위 기사단이 아니라 서쪽 신전에서 온 사람들이야.","JPN":"じっとしてて、弱虫。防衛騎士団じゃなくて、西方の神殿から来た人たちよ。","ENG":"Stay still, coward. Those aren’t Defense Knights. They’re from the Western Temple.","TWN":"你安靜啦，膽小鬼。他們不是護衛騎士團的人，他們是從西方神殿來的。"},"stage":{"bg":"UNDER","slots":{"L":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GRIL_KNIGHT_PAST_STAFF","face":"UNIT_SERIOUS"}}}},{"id":"L22_1","type":"dialog","speaker":"HOLY_KNIGHT_PAST_STAFF","text":{"KOREA":"약속한 대로 <color=#ffd34c>부활의 지팡이</color>를 가져왔어요, 사제님.","JPN":"約束どおり、<color=#ffd34c>復活の杖</color>を持ってきました、司祭様。","ENG":"I have brought the <color=#ffd34c>Staff of Resurrection</color> as promised, Your Grace.","TWN":"這是你要的<color=#ffd34c>復活之杖</color>，祭司大人。"},"stage":{"bg":"UNDER","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_PAST_STAFF","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"HOLY_KNIGHT_PAST_STAFF","text":{"KOREA":"대신전에서 직접 보셨을 테니까, 진품인지 아닌지는 감별할 필요 없겠죠?","JPN":"大神殿で直接見たはずですから、本物かどうか鑑定する必要はないでしょう？","ENG":"Since you have probably seen this in person at the Great Temple, there should be no need to confirm its authenticity, right?","TWN":"你應該有在大神殿中親眼見過，就不需要再鑑識真偽了吧？"},"stage":{"bg":"UNDER","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_PAST_STAFF","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"PRIESTESS_NPC_WEST_NULL","text":{"KOREA":"그래요. 확실히 그 찬란한 빛은 200년만에 다시 나타난 성녀의 징표…….","JPN":"そうですね。この眩い光は確かに200年ぶりに再び現れた聖女の証……","ENG":"That is true. Surely that radiant light is the sign of the Saintess who has reappeared after 200 years...","TWN":"嗯嗯，那耀眼的光芒，確實是睽違200年再次出現的聖女信物……"},"stage":{"bg":"UNDER","slots":{"L":null,"C":{"char_id":"PRIESTESS_NPC_WEST_NULL","face":"UNIT_IDLE"},"R":{"char_id":"KNIGHT_NPC_TEMPLE_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"PRIESTESS_NPC_WEST_NULL","text":{"KOREA":"진품이 틀림없군요. 아주 훌륭해요.","JPN":"本物で間違いありません。とても素晴らしい。","ENG":"There is no doubt that it is the real artifact. You did a great job.","TWN":"沒錯，你做得非常好。"},"stage":{"bg":"UNDER","slots":{"L":null,"C":{"char_id":"PRIESTESS_NPC_WEST_NULL","face":"UNIT_IDLE"},"R":{"char_id":"KNIGHT_NPC_TEMPLE_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_NULL","text":{"KOREA":"부활의 지팡이라면……. 성녀에게 주어진다는 성물 아니야?","JPN":"復活の杖って……　聖女に与えられるっていう聖物じゃなかった？","ENG":"The Staff of Resurrection... Isn’t that the Holy Relic bestowed upon the Saintess?","TWN":"復活之杖……不是賦予聖女的聖物嗎？"},"stage":{"bg":"UNDER","slots":{"L":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HOLY_KNIGHT_PAST_STAFF","face":"UNIT_IDLE"}}}}]`);export{e as default};